const clientId = env.get("SPOTIFY_CLIENT_ID") || "e249cffb68c848fcace0e60a7b4a7aa3";
const redirectUri = env.get("SPOTIFY_REDIRECT_URI") || "https://poikilitic-suzi-capably.ngrok-free.dev/spotify/callback";
const state = Math.random().toString(36).slice(2) + Date.now().toString(36);
global.set("spotify_oauth_state", state);

const scope = [
  "streaming",
  "user-read-email",
  "user-read-private",
  "user-read-playback-state",
  "user-read-currently-playing",
  "user-modify-playback-state"
].join(" ");

const params = new URLSearchParams({
  response_type: "code",
  client_id: clientId,
  scope,
  redirect_uri: redirectUri,
  state,
  show_dialog: "true"
});

msg.statusCode = 302;
msg.headers = { Location: "https://accounts.spotify.com/authorize?" + params.toString() };
msg.payload = "";
return msg;

const query = (msg.req && msg.req.query) || {};
const expectedState = global.get("spotify_oauth_state");

if (query.error) {
  msg.statusCode = 400;
  msg.payload = { error: query.error };
  return [null, msg];
}

if (!query.code || !query.state || query.state !== expectedState) {
  msg.statusCode = 400;
  msg.payload = { error: "Invalid Spotify OAuth callback state." };
  return [null, msg];
}

const clientId = env.get("SPOTIFY_CLIENT_ID") || "e249cffb68c848fcace0e60a7b4a7aa3";
const clientSecret = env.get("SPOTIFY_CLIENT_SECRET") || "55b37c551a1844d5b089ef9ebca143c9";
const redirectUri = env.get("SPOTIFY_REDIRECT_URI") || "https://poikilitic-suzi-capably.ngrok-free.dev/spotify/callback";

msg.method = "POST";
msg.url = "https://accounts.spotify.com/api/token";
msg.headers = {
  "Content-Type": "application/x-www-form-urlencoded",
  Authorization: "Basic " + Buffer.from(clientId + ":" + clientSecret).toString("base64")
};
msg.payload = new URLSearchParams({
  grant_type: "authorization_code",
  code: query.code,
  redirect_uri: redirectUri
}).toString();

return [msg, null];

const body = msg.payload || {};

if (msg.statusCode >= 400 || !body.access_token) {
  msg.statusCode = 500;
  msg.payload = { error: "Spotify token exchange failed.", details: body };
  return msg;
}

global.set("spotify_access_token", body.access_token);
if (body.refresh_token) {
  global.set("spotify_refresh_token", body.refresh_token);
}
global.set("spotify_expires_at", Date.now() + Number(body.expires_in || 3600) * 1000);

msg.statusCode = 302;
msg.headers = { Location: env.get("SPOTIFY_RETURN_URL") || "/sentient-stream/" };
msg.payload = "";
return msg;

const refreshToken = global.get("spotify_refresh_token");
const expiresAt = Number(global.get("spotify_expires_at") || 0);

if (!refreshToken || Date.now() < expiresAt - 5 * 60 * 1000) {
  return null;
}

const clientId = env.get("SPOTIFY_CLIENT_ID") || "e249cffb68c848fcace0e60a7b4a7aa3";
const clientSecret = env.get("SPOTIFY_CLIENT_SECRET") || "55b37c551a1844d5b089ef9ebca143c9";

msg.method = "POST";
msg.url = "https://accounts.spotify.com/api/token";
msg.headers = {
  "Content-Type": "application/x-www-form-urlencoded",
  Authorization: "Basic " + Buffer.from(clientId + ":" + clientSecret).toString("base64")
};
msg.payload = new URLSearchParams({
  grant_type: "refresh_token",
  refresh_token: refreshToken
}).toString();
return msg;

const body = msg.payload || {};
if (msg.statusCode >= 400 || !body.access_token) {
  node.warn("Spotify refresh failed: " + JSON.stringify(body));
  return null;
}

global.set("spotify_access_token", body.access_token);
if (body.refresh_token) {
  global.set("spotify_refresh_token", body.refresh_token);
}
global.set("spotify_expires_at", Date.now() + Number(body.expires_in || 3600) * 1000);
return null;

const accessToken = global.get("spotify_access_token");
if (!accessToken) {
  msg.statusCode = 200;
  msg.headers = { "Cache-Control": "no-store", "Content-Type": "application/json" };
  msg.payload = {
    access_token: null,
    connected: false,
    error: "Spotify is not connected. Visit /spotify/login first."
  };
  return msg;
}

msg.statusCode = 200;
msg.headers = { "Cache-Control": "no-store", "Content-Type": "application/json" };
msg.payload = {
  access_token: accessToken,
  connected: true,
  expires_at: global.get("spotify_expires_at") || null
};
return msg;

let baseUrl = String(env.get("LM_STUDIO_BASE_URL") || "http://host.docker.internal:1234");
if (baseUrl.endsWith("/")) baseUrl = baseUrl.slice(0, -1);
msg.method = "GET";
msg.url = baseUrl + "/v1/models";
msg.headers = { "Content-Type": "application/json" };
msg.payload = null;
return msg;

const ok = msg.statusCode < 400;
msg.statusCode = ok ? 200 : 502;
msg.headers = { "Content-Type": "application/json" };
msg.payload = ok ? { ok: true } : { ok: false, error: "LM Studio ping failed." };
return msg;

let body = msg.payload || {};
if (typeof body === "string") {
  try {
    body = JSON.parse(body);
  } catch (error) {
    body = {};
  }
}

const imageBase64 = body.image || "";
if (!imageBase64) {
  msg.statusCode = 400;
  msg.payload = { error: "Missing image field" };
  msg.headers = { "Content-Type": "application/json" };
  return [null, msg];
}

let baseUrl = String(env.get("LM_STUDIO_BASE_URL") || "http://host.docker.internal:1234");
if (baseUrl.endsWith("/")) baseUrl = baseUrl.slice(0, -1);

msg.method = "POST";
msg.url = baseUrl + "/v1/chat/completions";
msg.headers = { "Content-Type": "application/json" };
msg.payload = {
  model: "local-model",
  max_tokens: 260,
  temperature: 0.2,
  messages: [
    {
      role: "system",
      content: "You are a facial expression analyser and music recommender. Respond only with plain text. Do not use JSON, markdown, code fences, or bullet points."
    },
    {
      role: "user",
      content: [
        { type: "image_url", image_url: { url: "data:image/jpeg;base64," + imageBase64 } },
        {
          type: "text",
          text: [
            "Look at this webcam frame and identify the dominant facial expression.",
            "Also suggest exactly one real song that fits the mood.",
            "Return plain text using these labels exactly:",
            "face_detected: <true|false>",
            "mood_analysis: <1-2 sentences describing the emotional state>",
            "mood: <one of happy|sad|angry|surprised|fearful|disgusted|neutral>",
            "confidence: <0.0-1.0>",
            "title: <song title>",
            "artist: <artist name>",
            "reason: <one sentence why this song fits>",
            "If no face is visible, return face_detected: false, mood_analysis: no face detected, mood: neutral, confidence: 0, title: none, artist: none, reason: no song."
          ].join(" ")
        }
      ]
    }
  ]
};
return [msg, null];

if (msg.statusCode >= 400) {
  msg.statusCode = 502;
  msg.headers = { "Content-Type": "application/json" };
  msg.payload = {
    face_detected: false,
    mood: { mood: "neutral", confidence: 0 },
    source: "lm-studio",
    mood_analysis: "LM Studio returned " + msg.statusCode,
    suggestion: null,
    track: null,
    error: "LM Studio returned " + msg.statusCode,
  };
  return msg;
}

const lmData = msg.payload || {};
const raw = String(lmData.choices && lmData.choices[0] && lmData.choices[0].message && lmData.choices[0].message.content || "").trim();

function findMatch(text, regex, fallback = "") {
  const match = String(text || "").match(regex);
  return match ? String(match[1] || match[0]).trim() : fallback;
}

function parseConfidence(value) {
  const parsed = Number(String(value || "").trim());
  return Number.isFinite(parsed) ? Math.max(0, Math.min(1, parsed)) : 0;
}

function parseField(label, fallback = "") {
  const pattern = new RegExp("(?:^|\n|\r)\s*" + label + "\s*:\s*([^\n\r]+)", "i");
  const match = String(raw || "").match(pattern);
  return match ? String(match[1] || match[0]).trim() : fallback;
}

const faceDetectedRaw = parseField("face_detected", "false");
const moodAnalysis = parseField("mood_analysis", "");
const mood = parseField("(?:mood|emotion)", "neutral").toLowerCase();
const confidence = parseConfidence(parseField("confidence", "0"));
const title = parseField("(?:title|track|song)", "");
const artist = parseField("artist", "");
const reason = parseField("reason", "");
const faceDetected = /^(true|yes|1)$/i.test(faceDetectedRaw);
const safeMood = faceDetected ? mood : "neutral";
const safeConfidence = faceDetected ? confidence : 0;
const track = faceDetected && title && artist
  ? {
      title,
      artist,
      mood: { mood: safeMood, confidence: safeConfidence },
      reason,
      uri: null,
      album_art: null,
    }
  : null;

const result = {
  face_detected: faceDetected,
  mood: { mood: safeMood, confidence: safeConfidence },
  source: "lm-studio",
  mood_analysis: moodAnalysis || (faceDetected ? raw : "No face detected"),
  suggestion: track,
  track,
};

if (faceDetected && (!title || !artist)) {
  result.warning = "LM Studio returned no song suggestion.";
}

msg.statusCode = 200;
msg.headers = { "Content-Type": "application/json" };
msg.payload = result;
return msg;

let body = msg.payload || {};
if (typeof body === "string") {
  try {
    body = JSON.parse(body);
  } catch (error) {
    body = {};
  }
}

const suggestion = body.suggestion || body;
const title = String(suggestion.title || "").trim();
const artist = String(suggestion.artist || "").trim();
const searchQuery = [title, artist].filter(Boolean).join(" ").trim();
const accessToken = global.get("spotify_access_token");

if (!accessToken) {
  msg.statusCode = 401;
  msg.payload = { error: "Spotify is not connected. Visit /spotify/login first." };
  return [null, msg];
}

if (!searchQuery) {
  msg.statusCode = 400;
  msg.payload = { error: "Expected JSON body with a song title or artist." };
  return [null, msg];
}

msg.suggestion = { title, artist, mood: body.mood || null };
msg.method = "GET";
msg.url = "https://api.spotify.com/v1/search?type=track&limit=1&q=" + encodeURIComponent(searchQuery);
msg.headers = { Authorization: "Bearer " + accessToken };
msg.payload = null;
return [msg, null];

if (msg.statusCode >= 400) {
  msg.payload = { error: "Spotify search failed.", details: msg.payload };
  return [null, msg];
}

const item = msg.payload && msg.payload.tracks && msg.payload.tracks.items && msg.payload.tracks.items[0];

if (!item) {
  msg.statusCode = 404;
  msg.payload = { error: "No Spotify track found.", suggestion: msg.suggestion };
  return [null, msg];
}

const accessToken = global.get("spotify_access_token");
const artistName = (item.artists || []).map((artist) => artist.name).join(", ");
msg.track = {
  id: item.id,
  title: item.name,
  artist: artistName,
  uri: item.uri,
  album: item.album && item.album.name,
  album_art: item.album && item.album.images && item.album.images[0] && item.album.images[0].url,
  preview_url: item.preview_url,
  external_url: item.external_urls && item.external_urls.spotify,
  mood: msg.suggestion && msg.suggestion.mood
};

msg.method = "POST";
msg.url = "https://api.spotify.com/v1/me/player/queue?uri=" + encodeURIComponent(item.uri);
msg.headers = { Authorization: "Bearer " + accessToken };
msg.payload = null;
return [msg, null];

const queued = msg.statusCode >= 200 && msg.statusCode < 300;
const payload = { queued, spotifyStatus: msg.statusCode, track: msg.track };

if (!queued) {
  payload.queue_error = msg.payload || null;
}

const httpMsg = {
  ...msg,
  statusCode: queued ? 200 : 202,
  headers: { "Content-Type": "application/json" },
  payload
};

const uiMsg = { topic: "sentient-stream/queued", payload };
return [httpMsg, uiMsg];

const accessToken = global.get("spotify_access_token");
if (!accessToken) {
  msg.statusCode = 200;
  msg.headers = { "Content-Type": "application/json", "Cache-Control": "no-store" };
  msg.payload = {
    is_playing: false,
    track_name: null,
    artist: null,
    album_art: null,
    progress_ms: 0,
    duration_ms: 0,
    uri: null,
    connected: false,
    error: "Spotify is not connected. Visit /spotify/login first."
  };
  return [null, msg];
}

msg.method = "GET";
msg.url = "https://api.spotify.com/v1/me/player";
msg.headers = { Authorization: "Bearer " + accessToken };
msg.payload = null;
return [msg, null];

if (msg.statusCode === 204) {
  msg.statusCode = 200;
  msg.headers = { "Content-Type": "application/json", "Cache-Control": "no-store" };
  msg.payload = { is_playing: false, track_name: null, artist: null, album_art: null, progress_ms: 0, duration_ms: 0, uri: null, connected: true };
  return msg;
}

if (msg.statusCode >= 400) {
  msg.statusCode = 200;
  msg.headers = { "Content-Type": "application/json", "Cache-Control": "no-store" };
  msg.payload = {
    is_playing: false,
    track_name: null,
    artist: null,
    album_art: null,
    progress_ms: 0,
    duration_ms: 0,
    uri: null,
    connected: false,
    error: "Spotify player state failed.",
    details: msg.payload
  };
  return msg;
}

const body = msg.payload || {};
const item = body.item || {};
msg.statusCode = 200;
msg.headers = { "Content-Type": "application/json", "Cache-Control": "no-store" };
msg.payload = {
  is_playing: Boolean(body.is_playing),
  track_name: item.name || null,
  artist: item.artists ? item.artists.map((artist) => artist.name).join(", ") : null,
  album_art: item.album && item.album.images && item.album.images[0] && item.album.images[0].url,
  progress_ms: body.progress_ms || 0,
  duration_ms: item.duration_ms || 0,
  uri: item.uri || null,
  connected: true
};
return msg;

const accessToken = global.get("spotify_access_token");
if (!accessToken) {
  msg.statusCode = 401;
  msg.headers = { "Content-Type": "application/json" };
  msg.payload = { error: "Spotify is not connected. Visit /spotify/login first." };
  return [null, msg];
}

let body = msg.payload || {};
if (typeof body === "string") {
  try { body = JSON.parse(body); } catch (_) { body = {}; }
}

msg.method = "PUT";
msg.url = "https://api.spotify.com/v1/me/player";
msg.headers = { "Authorization": "Bearer " + accessToken, "Content-Type": "application/json" };
msg.payload = body;
return [msg, null];

const ok = msg.statusCode === 204 || (msg.statusCode >= 200 && msg.statusCode < 300);
msg.statusCode = ok ? 204 : msg.statusCode;
msg.headers = { "Content-Type": "application/json" };
if (!ok) {
  msg.payload = { error: "Playback transfer failed.", details: msg.payload };
} else {
  msg.payload = "";
}
return msg;

const accessToken = global.get("spotify_access_token");
if (!accessToken) {
  msg.statusCode = 401;
  msg.headers = { "Content-Type": "application/json" };
  msg.payload = { error: "Spotify is not connected. Visit /spotify/login first." };
  return [null, msg];
}

const deviceId = (msg.req && msg.req.query && msg.req.query.device_id) || "";
let body = msg.payload || {};
if (typeof body === "string") {
  try { body = JSON.parse(body); } catch (_) { body = {}; }
}

const qs = deviceId ? "?device_id=" + encodeURIComponent(deviceId) : "";
msg.method = "PUT";
msg.url = "https://api.spotify.com/v1/me/player/play" + qs;
msg.headers = { "Authorization": "Bearer " + accessToken, "Content-Type": "application/json" };
msg.payload = body;
return [msg, null];

const ok = msg.statusCode === 204 || (msg.statusCode >= 200 && msg.statusCode < 300);
const details = (!ok && msg.payload && msg.payload.error && msg.payload.error.message) ? msg.payload.error.message : null;
msg.statusCode = ok ? 204 : msg.statusCode;
msg.headers = { "Content-Type": "application/json" };
if (!ok) {
  msg.payload = { error: details ? "Spotify play failed: " + details : "Spotify play failed.", spotifyStatus: msg.statusCode };
} else {
  msg.payload = "";
}
return msg;
